// Outreach sequences -> fact_outreach_sequence_daily  (SNAPSHOT per run).
// Sequence-object counters are LIFETIME totals -> activity_date = run date (upserts in place).
// Funnel uses PROSPECT-LEVEL unique counts (so rates read as "% of prospects"):
//   prospects = numContactedProspects, opens = prospectOpenCount,
//   clicks = prospectClickCount, replies = numRepliedProspects.
// Region/pillar are derived from the CWSI naming convention; SEQUENCE_MAP overrides everything.
// Meetings/SQL/pipeline are NOT in the Outreach API (they come from Salesforce) -> meetings = 0.

// =====================================================================
// OPTIONAL manual overrides — only for sequences the parser gets wrong.
//   region: 'UKI' | 'BeLux' | 'NL' | 'UNASSIGNED'
//   pillar: one of the 5 Secure areas, or null
const SEQUENCE_MAP = {
  // '173': { region: 'UKI', pillar: 'Secure Operations' },
};
// =====================================================================

const REGIONS = ['UKI', 'BeLux', 'NL', 'UNASSIGNED'];
const PILLARS = ['Secure AI', 'Secure Data', 'Secure Endpoints', 'Secure Identity', 'Secure Operations'];
const SKIP = /dummy|(^|[^a-z])test\b|test of sales|test sales|test \d/i;   // drop test/dummy sequences

function regionFromName(nm) {
  const n = String(nm || '').toLowerCase();
  if (/belux/.test(n)) return 'BeLux';
  if (/(^|[^a-z])nl([^a-z]|$)|netherlands|gemeente/.test(n)) return 'NL';
  if (/uk&i|uk & i|\buki\b|united kingdom|\buk\b|ireland|dublin/.test(n)) return 'UKI';
  return 'UNASSIGNED';
}
function pillarFromName(nm) {
  const n = String(nm || '').toLowerCase();
  if (/secure ai|copilot|(^|[^a-z])ai([^a-z]|$)|agents? 365/.test(n)) return 'Secure AI';
  if (/secure data|data security|data is an asset/.test(n)) return 'Secure Data';
  if (/secure endpoint|endpoint|\buem\b|device/.test(n)) return 'Secure Endpoints';
  if (/secure identity|identity/.test(n)) return 'Secure Identity';
  if (/secure operations|secops|threat protection|frontline operations/.test(n)) return 'Secure Operations';
  return null;
}
function pick(a, names) { for (const k of names) { if (a[k] != null) return Number(a[k]) || 0; } return 0; }

const today = new Date().toISOString().slice(0, 10);
const out = [];
for (const item of $input.all()) {
  const body = item.json || {};
  const list = Array.isArray(body.data) ? body.data : (Array.isArray(body) ? body : [body]);
  for (const seq of list) {
    if (!seq || seq.id == null) continue;
    const a = seq.attributes || {};
    const id = String(seq.id);
    const name = a.name || '';
    if (SKIP.test(name)) continue;

    let region = null, pillar = null;
    if (SEQUENCE_MAP[id]) { region = SEQUENCE_MAP[id].region; pillar = SEQUENCE_MAP[id].pillar; }
    if (!region) region = regionFromName(name);
    if (!pillar) pillar = pillarFromName(name);
    if (REGIONS.indexOf(region) < 0) region = 'UNASSIGNED';
    if (pillar && PILLARS.indexOf(pillar) < 0) pillar = null;

    out.push({ json: {
      activity_date: today,
      sequence_id: id,
      sequence_name: name,
      region_code: region,
      pillar_name: pillar,                                   // null allowed
      prospects: pick(a, ['numContactedProspects', 'prospectContactedCount', 'scheduleCount']),
      opens:     pick(a, ['prospectOpenCount', 'openCount']),
      clicks:    pick(a, ['prospectClickCount', 'clickCount']),
      replies:   pick(a, ['numRepliedProspects', 'prospectReplyCount', 'replyCount']),
      meetings:  0,
      enabled:   a.enabled === true
    } });
  }
}
if (out.length === 0) {
  throw new Error('Outreach: no sequences after parse - check the OAuth2 credential, scope read_sequences, and the Accept header.');
}
return out;
